3_real_world_example.code:
function makeCounter() {
  let count = 0; // stored in makeCounter's Lexical Environment

  return function increment() {
    count++;          // outer reference walks up to makeCounter's env
    return count;
  };
}

const counter = makeCounter();
console.log(counter()); // 1
console.log(counter()); // 2
// makeCounter's Lexical Environment is kept alive by the closure

6_edge_case.code:
// With let: each iteration has its own Lexical Environment
const funcs = [];
for (let i = 0; i < 3; i++) {
  funcs.push(() => i); // each closure captures its own 'i'
}
console.log(funcs[0]()); // 0
console.log(funcs[1]()); // 1
console.log(funcs[2]()); // 2

// With var: all closures share the SAME variable binding
const funcsVar = [];
for (var j = 0; j < 3; j++) {
  funcsVar.push(() => j);
}
console.log(funcsVar[0]()); // 3 (surprising!)
